// Every known EPL rider entry: the previous 67-strong 60-70cm list plus all of the
// "Final Start list 28th June 2026" classes (dressage + SJ3 + SJ5 + SJ7).
// Renumbered sequentially so each entry has a unique `sl` for the picker.
export const ALL_EPL_RIDERS: StartListRider[] = [
  ...SJ1_60_70_RIDERS,
  ...JUNIOR_DRESSAGE_D3_RIDERS,
  ...SJ3_90_100_RIDERS,
  ...SJ5_110_115_RIDERS,
  ...SJ7_130_RIDERS,
].map((r, i) => ({ ...r, sl: i + 1 }));

// Pick the right start list for a standalone show-jumping sheet from its slug.
// Matches the class height/number in the sheet name; falls back to the 90-100CM (SJ3) list.
export function startListForSlug(slug: string): StartListRider[] {
  const s = slug.toLowerCase();
  if (s.includes("110") || s.includes("115") || s.includes("sj5")) return SJ5_110_115_RIDERS;
  if (s.includes("130") || s.includes("sj7")) return SJ7_130_RIDERS;
  if (s.includes("60-70") || s.includes("60") || s.includes("70") || s.includes("sj1")) return SJ1_60_70_RIDERS;
  if (s.includes("90") || s.includes("100") || s.includes("sj3")) return SJ3_90_100_RIDERS;
  return SJ3_90_100_RIDERS;
}
